body.pre:
* { box-sizing: border-box; }

body {
  margin: 0;
  font-family: 'Abel', sans-serif;
  letter-spacing: 1px;
  background: #f0f7ff;
}

input, select, button {
  width: 100%;
  padding: 12px;
  margin-top: 10px;
  border-radius: 6px;
  border: 1px solid #ccc;
}

button {
  background: #1F2A44;
  color: white;
  border: none;
  cursor: pointer;
  outline: none;
}

button:hover {
  background: #22385F;
}

/* PORTAL */
.portal {
  display: flex;
  min-height: 100vh;
}

.sidebar {
  width: 230px;
  background: #2A4474;
  color: white;
  font-family: 'Abel', sans-serif;
  position: relative;
}

.sidebar h3 {
  text-align: center;
  margin-bottom: 25px;
}

.sidebar a {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 14px 18px;
  color: white;
  text-decoration: none;
  cursor: pointer;
}

.sidebar a:hover {
  background: #22385F;
}

.sidebar-logo { 
  display:block; 
  width:48px; 
  height:48px; 
  margin:18px auto; 
  border-radius:8px; 
}
.sidebar-top { 
  padding:12px 16px; 
}
.sidebar-top h3 { 
  margin: 0; 
  font-size:1.05rem; 
  font-weight:700; }
.sidebar-nav { 
  display:flex; 
  flex-direction:column; 
  gap:8px; 
  padding:12px 8px; 
}
.sidebar a .icon { 
  width:18px; 
  height:18px; 
  object-fit:contain; 
  filter: brightness(1.1) invert(0.98) saturate(0.0); 
}
.icon-wrapper { 
  width:36px; 
  height:36px; 
  display:inline-flex; 
  align-items:center; 
  justify-content:center; 
  background: rgba(255,255,255,0.04); 
  border-radius:8px; 
}
.sidebar a span { 
  font-size:0.95rem; 
}
.sidebar-nav a { 
  position: relative;
  padding:10px 12px;
  display:flex; 
  align-items:center; 
  gap:12px; 
}
.sidebar-nav a.active { 
  background: rgba(0,0,0,0.12); 
  border-radius:8px; }
.sidebar-nav a:hover { 
  background: rgba(0,0,0,0.08); 
}

/* Profile dropdown */
.profile-wrapper { 
  position: relative; 
  display:inline-block; 
  margin-left:12px; 
}
.profile-btn { 
  background: transparent; 
  border: none; 
  padding: 0; 
  cursor: pointer; 
  display:inline-flex; 
  align-items:center; 
}
.profile-avatar { 
  width:36px; 
  height:36px; 
  display:inline-flex; 
  align-items:center; 
  justify-content:center; 
  border-radius:50%; 
  background: rgba(255,255,255,0.08); 
  overflow: hidden; 
}
.profile-avatar img.profile-img { 
  width:100%; 
  height:100%; 
  object-fit:cover; 
  display:block; }

.profile-menu { 
  position: absolute;
  right: 0; 
  top: 44px; 
  width:260px; 
  background: #fff; 
  color:#222; 
  border-radius:8px; 
  box-shadow: 0 8px 30px rgba(0,0,0,0.12); 
  overflow: hidden; 
  z-index: 60; 
}
.profile-menu .profile-card { 
  padding: 16px; 
  display:flex; 
  gap:12px; 
  align-items:center; 
}
.profile-avatar-large {
  width:56px; 
  height:56px; 
  display:flex; 
  align-items:center; 
  justify-content:center; 
  border-radius:50%; 
  background:#f7f7f7; 
  overflow:hidden; 
}
.profile-avatar-large img.profile-img-large { 
  width:100%; 
  height:100%;
  object-fit:cover; 
  display:block; 
}
.profile-welcome { 
  font-size:0.9rem; 
  color:#222; 
}
.profile-menu hr { 
  margin: 0; 
  border: none; 
  border-top: 1px solid #efefef; 
}
.profile-actions { 
  list-style:none; 
  margin:0; 
  padding:8px 0; 
}
.profile-actions li a { 
  display:block; 
  padding:10px 14px; 
  color:#333; 
  text-decoration:none; 
  font-size:0.95rem; 
}
.profile-actions li a:hover { 
  background:#f6f7fb; 
}
.badge { 
  display:inline-block; 
  margin-left:8px; 
  border:1px solid #f05a5a; 
  color:#f05a5a; 
  padding:3px 8px; 
  border-radius:8px; 
  font-size:0.75rem; 
}
.hidden { 
  display:none; 
}

.main {
  flex: 1;
  padding: 25px;
}

.topbar {
  margin-bottom: 20px;
}

/* Topbar inner white container that matches the provided design */
.topbar-inner {
  background: #fff;
  width: 100%;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  padding: 10px 16px;
  border-radius: 12px;
  box-shadow: 0 6px 18px rgba(15, 45, 78, 0.06);
  border: 1px solid rgba(15,45,78,0.04);
}

.topbar-inner h1 {
  margin: 0;
  font-size: 1.05rem;
  color: #0f2d57;
  font-weight: 600;
}

/* Search centered */
.search-profile {
  display: flex;
  align-items: center;
  gap: 12px;
  margin-left: 12px;
}

.top-search {
  display: inline-flex;
  align-items: center;
  background: #f6f9fb;
  border: 1px solid #e6eef6;
  padding: 8px 12px;
  border-radius: 8px;
  min-width: 280px;
  max-width: 52vw;
}
.top-search input { all: unset; width:100%; }

/* Right side controls: language, action icons, profile */
.right-controls { 
  display:flex; 
  align-items:center; 
  gap:10px; 
}
.icon-button { 
  width:36px; 
  height:36px; 
  display:inline-flex; 
  align-items:center; 
  justify-content:center; 
  border-radius:50%; 
  background:#f3f7fb; 
  border:1px solid rgba(15,45,78,0.04); 
  cursor:pointer; 

}
.icon-button img { 
  width:18px; 
  height:18px; 
  object-fit:contain; }

.profile-wrapper { 
  position: relative; 
  display:flex; 
  align-items:center; 
  gap:8px; 
}
.profile-name { 
  font-size:0.9rem; 
  color:#0f2d57; 
  font-weight:600; 
}
.profile-btn { 
  background: transparent; 
  border: none; 
  padding: 0; 
  cursor: pointer; 
  display:inline-flex; 
  align-items:center; }
.profile-avatar { 
  width:36px; 
  height:36px; 
  display:inline-flex; 
  align-items:center; 
  justify-content:center; 
  border-radius:50%; 
  background: rgba(255,255,255,0.0); 
  overflow: hidden; 
}
.profile-avatar img.profile-img { 
  width:100%; 
  height:100%; 
  object-fit:cover; 
  display:block; 
}

.banner {
  background: linear-gradient(180deg, #2A4474);
  color: white;
  padding: 25px;
  border-radius: 14px;
  margin-bottom: 20px;
}

.grid {
  display: grid;
  grid-template-columns: repeat(4, minmax(140px, 1fr));
  gap: 12px;
  margin-bottom: 16px;
  align-items: start;
}

.card {
  background: white;
  padding: 10px 12px;
  border-radius: 10px;
  box-shadow: 0 4px 10px rgba(0,0,0,0.05);
  min-height: 72px;
}

.card h3 {
  margin: 0;
  font-size: 1.25rem;
  line-height: 1;
}

.card p {
  margin: 6px 0 0 0;
  font-size: 0.9rem;
  color: #555;
}

table {
  width: 100%;
  border-collapse: collapse;
}

th, td {
  padding: 10px;
  border-bottom: 1px solid #ddd;
  text-align: left;
}

.hidden {
  display: none;
}

.schedule-table {
  width: 100%;
  border-collapse: collapse;
  text-align: center;
}

.schedule-table th {
  background: #f5f6fa;
  padding: 10px;
  font-weight: 600;
}

.schedule-table td {
  padding: 12px;
  border: 1px solid #ddd;
}

.card table {
  width: 100%;
  border-collapse: collapse;
}

.card table th {
  background: #f0f0f0;
  padding: 10px;
}

/* Quick actions on dashboard */
.quick-actions{
  display:flex;
  gap:12px;
  margin-top:12px
}
.action-card{
  display:flex;
  align-items:center;
  gap:12px;
  padding:12px 16px;
  border-radius:10px;
  background:#fff;
  box-shadow:0 6px 18px rgba(15,45,78,0.04);
  cursor:pointer;
  border:1px solid rgba(15,45,78,0.03);
  transition:transform 180ms ease,box-shadow 180ms ease,opacity 120ms
}
.action-card .action-icon{
  width:48px;
  height:48px;
  border-radius:8px;
  display:flex;
  align-items:center;
  justify-content:center;
  font-size:20px
}
.action-card .action-body .action-title{
  font-weight:700;
  color:#0f2d57
}
.action-card .action-body .action-sub{
  font-size:0.9rem;
  color:#666
}
.action-card:hover{
  transform:translateY(-6px);
  box-shadow:0 18px 38px rgba(15,45,78,0.12)
}
.action-card:active{
  transform:translateY(-2px) scale(0.997)
}
.action-card:focus{
  outline:none
}
.action-card:focus-visible{
  box-shadow:0 18px 38px rgba(15,45,78,0.12);
  border-color:rgba(15,45,78,0.08)
}
.action-card:focus-visible{
  box-shadow:0 18px 38px rgba(15,45,78,0.12);
  border-color:rgba(15,45,78,0.08)
}
/* Colored icon backgrounds */
.action-icon.blue{
  background:rgba(42,68,116,0.08);
  color:var(--accent-strong)
}
.action-icon.green{
  background:rgba(34,197,94,0.08);
  color:var(--green)
}

/* Modal styles for Add Class */

.modal{
  position:fixed;
  top:0;left:0;
  width:100%;
  height:100%;
  display:flex;
  align-items:center;
  justify-content:center;
  padding:24px;
  background:rgba(15,45,78,0.35);z-index:120
}
.modal.hidden{
  display:none
}
.modal-dialog
{background:#fff;
  border-radius:12px;
  padding:18px;
  width:420px;
  max-width:100%;
  max-height:90vh;
  overflow:auto;
  box-shadow:0 24px 60px rgba(15,45,78,0.2);
  transform:translateY(6px) scale(0.98);
  opacity:0;
  transition:transform 180ms cubic-bezier(.2,.9,.2,1),opacity 180ms ease
}
.modal:not(.hidden) .modal-dialog{
  transform:translateY(0) scale(1);
  opacity:1
}
.modal-dialog h3{
  margin:0 0 12px 0
}
.modal-dialog label{
  display:block;font-size:0.9rem;color:#333;margin-bottom:10px
}
.modal-dialog input[type=text], .modal-dialog input[type=time], .modal-dialog select{
  width:100%;
  padding:10px;
  border-radius:8px;
  border:1px solid #e6e9ee
}
.btn-primary{
  background:var(--accent-strong);
  color:#fff;
  border:none;
  padding:10px 14px;
  border-radius:8px;
  cursor:pointer
}
.btn-cancel{
  background:#fff;
  border:1px solid #e6e9ee;
  padding:10px 14px;
  border-radius:8px;
  cursor:pointer
}

.card table td {
  padding: 10px;
  border-bottom: 1px solid #ddd;
}

/* Timetable / Schedule styles */
.schedule-card { 
  padding: 18px; 
}
.schedule-header { 
  display:flex; 
  align-items:center; 
  justify-content:space-between; 
  gap:12px; 
  margin-bottom:18px; 
}
.schedule-header h2 { 
  margin:0; 
  font-size:1.2rem; 
  color:#0f2d57; 
}
.schedule-header .muted { 
  margin:4px 0 0 0; 
  color:#6b7280; 
  font-size:0.95rem; 
}
.btn-add { 
  background:#1F6FEB; 
  color:#fff; 
  border:none; 
  padding:10px 14px; 
  border-radius:10px; 
  cursor:pointer; 
  font-weight:600; 
}
.btn-add:hover { 
  background:#145ed6; 
}

.timetable { 
  background: #fff; 
  padding: 12px; 
  border-radius: 12px; 
  box-shadow: 0 8px 20px rgba(15,45,78,0.04); 
  border: 1px solid rgba(15,45,78,0.03); 
}
.timetable-grid { 
  display: grid; 
  grid-template-columns: 110px repeat(7, 1fr); 
  gap: 16px; 
  align-items: start; 
}
.timetable-head { 
  font-weight:700; 
  padding:12px 8px; 
  color:#22385F; 
  text-align:left; 
}
.time-head { 
  text-align:center; 
}
.time-cell { 
  padding: 12px 8px; 
  text-align:center; 
  color:#374151; 
  font-weight:600; }
.day-cell { 
  min-height: 110px; 
}

.class-card { 
  background: #eef6ff; 
  border-radius: 8px; 
  display:flex; 
  gap:12px; 
  align-items:flex-start; 
  padding:10px; 
  position:relative; 
  overflow:hidden; 
}
.class-accent { 
  width:6px; 
  background:#2A74E6; 
  border-radius:4px; 
  margin-left:-6px; 
}
.class-body { 
  padding:4px 6px; 
}
.class-title { 
  font-weight:700; 
  color:#0f2d57; 
  margin-bottom:4px; 
}
.class-sub { 
  color:#6b7280; 
  margin-bottom:8px; 
}
.class-meta { 
  font-size:0.85rem; 
  color:#6b7280; 
  margin-bottom:4px; 
}

@media (max-width: 900px) {
  .timetable-grid { 
    grid-template-columns: 80px repeat(2, 1fr); 
  }
  /* hide later day columns on smaller screens */
  .timetable-head:nth-child(n+4), .timetable-head:nth-child(n+5), .timetable-head:nth-child(n+6), .timetable-head:nth-child(n+7), .timetable-head:nth-child(n+8) { 
    display:none; 
  }
}

/* Dashboard layout (search, quick actions, stats) */
.dashboard-top { 
  display:flex; 
  flex-direction:column; 
  gap:12px; 
  margin-bottom:18px; 
}
.current-date { 
  color:#6b7280; 
  font-size:0.95rem; 
}
.search-large input { 
  width:100%; 
  padding:18px 20px; 
  border-radius:12px; 
  border:1px solid #e6eef6; 
  background:#f9fbfd; 
  box-shadow: 0 6px 18px rgba(15,45,78,0.03); 
  font-size:1rem; 
}

.quick-actions {
  display:flex;
  gap:18px;
  margin: 10px 0 18px 0;
}
.action-card { 
  display:flex; 
  gap:14px; 
  align-items:center; 
  background:#fff; 
  padding:16px; 
  border-radius:12px; 
  flex:1; box-shadow:0 6px 18px rgba(15,45,78,0.04); 
  border:1px solid rgba(15,45,78,0.03); 
}
.action-icon { 
  width:52px; 
  height:52px; 
  border-radius:10px; 
  display:flex; 
  align-items:center; 
  justify-content:center; 
  font-size:20px; 
  color:#fff; 
  flex-shrink:0; 
}
.day-cell { 
  min-height: 110px; 
  padding: 12px;
  background: transparent; /* keep empty slots visually blank until populated */
}

.action-icon.purple {
  background:#f3e9ff; 
  color:#8B5CF6; 
}
.action-body .action-title { 
  font-weight:700; 
  color:#0f2d57; 
}
.action-body .action-sub { 
  color:#6b7280; 
  margin-top:6px; 
}

.stats-cards { 
  display:grid; 
  grid-template-columns: repeat(3, 1fr); 
  gap:18px; margin-top:6px; 
}
.stat-card { 
  background:#fff; 
  padding:18px; 
  border-radius:12px; 
  display:flex; 
  align-items:center; 
  justify-content:space-between; 
  box-shadow:0 6px 18px rgba(15,45,78,0.04); 
  border:1px solid rgba(15,45,78,0.03); 
}
.stat-label { 
  color:#6b7280; 
  font-size:0.95rem; 
}
.stat-value { 
  font-size:1.6rem; 
  font-weight:700; color:#0f2d57; margin-top:6px; 
}
.stat-icon {
  width:48px; 
  height:48px; 
  border-radius:10px; 
  display:flex; 
  align-items:center; 
  justify-content:center; 
  color:#fff; 
  font-size:18px; 
  flex-shrink:0; 
}
.stat-icon.blue { 
  background:#1F6FEB; 
}
.stat-icon.green { 
  background:#06C167; 
}
.stat-icon.orange { 
  background:#FF7A00; 
}
.stat-icon.purple { 
  background:#A855F7; 
}
.stat-icon.red { 
  background:#F05252; 
}

@media (max-width: 900px) {
  .quick-actions { 
    flex-direction:column; 
  }
  .stats-cards { 
    grid-template-columns: repeat(2, 1fr); 
  }
}

/* Sections */
.section { display: none; }
.section.active { display: block; }
#schedule.section.active { display: flex; flex-direction: column; gap: 12px; }
#schedule .schedule-card { margin-top: 0; }

/* Chart container */
#attendanceChart { width: 100% !important; }

/* Simple calendar */
#calendar { font-family: 'Abel', sans-serif; }
.calendar-grid { 
  display: grid; 
  grid-template-columns: repeat(7,1fr); 
  gap:6px; width:100%; 
  grid-auto-rows: 48px; }
.calendar-day { 
  padding:6px; 
  text-align:center; 
  border-radius:8px; 
  box-sizing: border-box; }
.calendar-day.header { 
  font-weight:700; color:#6b7280; 
  display:flex; align-items:center; 
  justify-content:center; 
  min-height:34px; }
.calendar-day.cell { 
  background:#fff; 
  border:1px solid #f0f0f0; 
  box-shadow:0 4px 10px rgba(0,0,0,0.03); 
  display:flex; align-items:center; 
  justify-content:center; 
  min-height:44px; }
.calendar-day.cell.today { 
  background: #2A4474; 
  color: white; }

/* Calendar header and nav */
.calendar-header { 
  display:flex; 
  justify-content:space-between; 
  align-items:center; 
  gap:10px; 
  margin-bottom:8px; }
.calendar-date-label { 
  font-weight:700; }
.calendar-nav { 
  display:flex; 
  gap:6px; 
  align-items:center; }
.nav-btn { 
  background: transparent; 
  border: 1px solid #e5e7eb; 
  padding:4px 8px; 
  border-radius:6px; 
  cursor:pointer; 
  font-size:0.9rem; 
  line-height:1; 
  min-width:34px; 
  height:30px; }
.nav-btn:hover { 
  background:#f3f4f6; }
.calendar-day.cell.selected { 
  outline: 3px solid rgba(42,68,116,0.12); 
  box-shadow: 0 6px 16px rgba(42,68,116,0.06); }

/* Color the previous button arrow to match topbar accent */
#cal-prev {
  color: #0f2d57;
  border-color: rgba(15,45,78,0.08);
  background: transparent;
}
#cal-prev:hover {
  background: rgba(15,45,78,0.04);
}

/* Style the next button similarly */
#cal-next {
  color: #0f2d57;
  border-color: rgba(15,45,78,0.08);
  background: transparent;
}
#cal-next:hover {
  background: rgba(15,45,78,0.04);
}

@media (max-width: 800px) {
  .portal { 
    flex-direction: column; 
  }
  .sidebar { 
    width: 100%; 
    display:flex; 
    gap:8px; 
    overflow:auto 
  }
  .main { 
    padding: 12px; 
  }
  .grid { 
    grid-template-columns: repeat(2,1fr); }
  .topbar h1 { 
    font-size:1.1rem
  }
}

/* Widgets: chart + calendar layout */
.widgets { 
  display:grid; 
  grid-template-columns: minmax(320px, 640px) 320px; 
  gap:20px; 
  align-items:start; 
}
.widgets .chart-card { 
  padding: 16px; 
  display:flex; 
  align-items:center; 
  justify-content:center; 
}
.widgets .calendar-card { 
  padding: 12px; }

/* Limit chart size so calendar always fits */
#attendanceChart { 
  max-width: 100%; 
  max-height: 360px; 
  width:100% !important; 
  height:auto !important; 
  display:block; 
}

.container{
  max-width:1100px;
  margin:28px auto;padding:20px
}
.topCard{
  background:var(--card);
  padding:18px;
  border-radius:12px;
  border:1px solid #eee;
  display:block
}
.topCard .topLeft{
  display:inline-block
}
.topCard .topRight{
  float:right
}
.top h1{
  margin:0;font-size:22px
}
.muted{
  color:var(--muted);
  font-size:13px
}
.topRight button{
  background:#fff;
  border:1px solid #e6e9ee;
  padding:8px 12px;
  border-radius:8px;
  margin-left:8px;
  cursor:pointer
}
.controls{
  display:flex;
  gap:16px;
  align-items:flex-end;
  margin-top:14px
}
.field{
  display:flex;
  flex-direction:column
}
.field .label{
  font-size:12px;
  color:var(--muted);
  margin-bottom:6px
}

select,
input[type="date"] {
  padding: 10px;
  border-radius: 8px;
  border: 1px solid #e6e9ee;
  width: 220px;
}

.viewMode {
  margin-left: auto;
}

.modes {
  display: flex;
  gap: 8px;
}

.mode {
  padding: 8px 12px;
  border-radius: 12px;
  border: none;
  background: #f3f6f9;
  cursor: pointer;
}

.mode.active {
  background: var(--accent);
  color: #fff;
}

.stats {
  display: flex;
  gap: 16px;
  margin-top: 18px;
}

.card {
  background: var(--card);
  padding: 20px;
  border-radius: 10px;
  flex: 1;
  border: 1px solid #eee;
}

.card small {
  display: block;
  color: var(--muted);
  margin-bottom: 10px;
}

.card strong {
  font-size: 20px;
}

.presentBadge {
  color: var(--green);
  font-size: 13px;
}

.presentPct {
  color: var(--green);
  font-weight: 600;
}

.tableWrap {
  margin-top: 18px;
  background: var(--card);
  border-radius: 10px;
  border: 1px solid #eee;
  padding: 8px;
}

.studentTable {
  width: 100%;
  border-collapse: collapse;
}

.studentTable thead th {
  text-align: left;
  padding: 14px 16px;
  border-bottom: 1px solid #f0f2f5;
  color: var(--muted);
}

.studentTable tbody td {
  padding: 14px 16px;
  border-bottom: 1px solid #f6f7f9;
  vertical-align: middle;
}

.studentRow {
  display: flex;
  align-items: center;
  gap: 12px;
}

.avatar {
  width: 44px;
  height: 44px;
  border-radius: 50%;
  object-fit: cover;
}

.studentName {
  font-weight: 600;
}

.smallMuted {
  display: block;
  color: var(--muted);
  font-size: 13px;
}

.statusBtns {
  display: flex;
  gap: 10px;
}

.pill {
  padding: 8px 12px;
  border-radius: 12px;
  border: 1px solid #e6e9ee;
  background: #fafafa;
  cursor: pointer;
  font-weight: 600;
}

.pill.present {
  border-color: var(--green);
  color: var(--green);
  background: rgba(34, 197, 94, 0.06);
}

.pill.absent {
  border-color: var(--red);
  color: var(--red);
  background: rgba(239, 68, 68, 0.06);
}

.pill.late {
  border-color: #d1d5db;
  color: #374151;
  background: #f8fafc;
}

.pill.active {
  box-shadow: inset 0 0 0 2px rgba(0, 0, 0, 0.03);
}

.saveRow {
  display: flex;
  justify-content: flex-end;
  margin-top: 14px;
}

.save {
  background: var(--accent);
  color: #fff;
  padding: 12px 18px;
  border-radius: 10px;
  border: none;
  cursor: pointer;
}

.save.fixed {
  position: fixed;
  right: 28px;
  bottom: 28px;
}

@media (max-width: 800px) {
  .controls {
    flex-direction: column;
    align-items: stretch;
  }

  .viewMode {
    margin-left: 0;
  }
}

@media (max-width: 980px) {
  .widgets { 
    grid-template-columns: 1fr; 
  }
  .widgets .calendar-card { 
    order: 2 
  }
  .widgets .chart-card { 
    order: 1 
  }
}
